const body = $input.first().json.body || $input.first().json;
const msg = body.message || body;
const call = msg.call || {};

const assistantId = call.assistantId || call.assistant?.id || msg.assistantId || msg.assistant?.id || '';
const callId = call.id || msg.callId || '';
const callerNumber = call.customer?.number || msg.customer?.number || null;

let toolName = 'unknown';
let toolParams = {};
let toolCallId = null;

const parseArgs = (args) => {
  if (!args) return {};
  if (typeof args === 'object') return args;
  try { return JSON.parse(args); } catch(e) { return {}; }
};

if (msg.toolWithToolCallList && msg.toolWithToolCallList[0]) {
  const t = msg.toolWithToolCallList[0];
  toolName = t.toolCall?.function?.name || t.function?.name || 'unknown';
  toolParams = parseArgs(t.toolCall?.function?.arguments || t.function?.arguments);
  toolCallId = t.toolCall?.id || t.id || null;
} else if (msg.toolCalls && msg.toolCalls[0]) {
  const t = msg.toolCalls[0];
  toolName = t.function?.name || 'unknown';
  toolParams = parseArgs(t.function?.arguments);
  toolCallId = t.id || null;
} else if (msg.toolCallList && msg.toolCallList[0]) {
  const t = msg.toolCallList[0];
  toolName = t.function?.name || 'unknown';
  toolParams = parseArgs(t.function?.arguments);
  toolCallId = t.id || null;
} else if (msg.functionCall) {
  toolName = msg.functionCall.name || 'unknown';
  toolParams = msg.functionCall.parameters || {};
  toolCallId = null;
}

return [{
  json: {
    assistant_id: assistantId,
    call_id: callId,
    caller_number: callerNumber,
    tool_name: toolName,
    tool_params: toolParams,
    tool_call_id: toolCallId
  }
}];

const raw = $input.first().json;
const config = Array.isArray(raw) ? raw[0] : raw;
const tool = $('Extract Tool Call').first().json;

if (!config || !config.user_id) {
  return [{ json: {
    config_found: false,
    tool_name: '_no_config_',
    tool_call_id: tool.tool_call_id,
    fallback_message: 'I apologize, I am unable to process your request at the moment. Please try again or call back later.'
  }}];
}

return [{
  json: {
    config_found: true,
    user_id: config.user_id,
    business_name: config.business_name || 'us',
    business_hours: config.business_hours || {},
    calendar_id: config.calendar_id || '',
    notification_email: config.notification_email || '',
    zapier_webhook_url: config.zapier_webhook_url || '',
    zapier_enabled: config.zapier_enabled || false,
    selected_plan: config.selected_plan || 'lite',
    timezone: config.timezone || 'America/Cayman',
    appointment_duration_minutes: config.appointment_duration_minutes || 30,
    assistant_id: tool.assistant_id,
    call_id: tool.call_id,
    caller_number: tool.caller_number,
    tool_name: tool.tool_name,
    tool_params: tool.tool_params,
    tool_call_id: tool.tool_call_id
  }
}];

const ctx = $('Merge Config + Tool').first().json;
const rawTime = (ctx.tool_params || {}).preferred_time || '';
const tz = ctx.timezone || 'America/New_York';

let parseValid = false;
let isoString = '';
let humanString = rawTime;

// Attempt 1: Luxon ISO (strict)
try {
  const dt = DateTime.fromISO(rawTime, { setZone: true });
  if (dt.isValid) {
    parseValid = true;
    isoString = dt.toUTC().toISO();
    humanString = dt.setZone(tz).toLocaleString(DateTime.DATETIME_FULL);
  }
} catch(e) {}

// Attempt 2: JS Date fallback
if (!parseValid && rawTime) {
  try {
    const d = new Date(rawTime);
    if (!isNaN(d.getTime())) {
      parseValid = true;
      isoString = d.toISOString();
      humanString = d.toLocaleString('en-US', { timeZone: tz, dateStyle: 'long', timeStyle: 'short' });
    }
  } catch(e) {}
}

return [{
  json: {
    ...ctx,
    parse_valid: parseValid,
    preferred_time_iso: parseValid ? isoString : null,
    preferred_time_human: humanString,
    raw_preferred_time: rawTime,
    tool_params: {
      ...(ctx.tool_params || {}),
      preferred_time: parseValid ? isoString : rawTime
    }
  }
}];

const ctx = $('Merge Config + Tool').first().json;
const events = $input.all().map(i => i.json).filter(e => e && e.id);
const requested = ctx.tool_params.requested_time;
const durMin = ctx.appointment_duration_minutes || 30;
const businessName = ctx.business_name;

let conflict = null;
try {
  const reqStart = new Date(requested).getTime();
  const reqEnd = reqStart + durMin * 60000;
  for (const e of events) {
    const eStart = new Date(e.start?.dateTime || e.start?.date).getTime();
    const eEnd = new Date(e.end?.dateTime || e.end?.date).getTime();
    if (reqStart < eEnd && reqEnd > eStart) { conflict = e; break; }
  }
} catch(err) {}

const available = !conflict;
const result = available
  ? `That time is available. Would you like me to book it?`
  : `I'm sorry, that time is not available. Please suggest another time.`;

return [{ json: { result, available, tool_call_id: ctx.tool_call_id } }];

const ctx = $('Merge Config + Tool').first().json;
const phone = ctx.tool_params.caller_phone || ctx.caller_number || '';
const events = $input.all().map(i => i.json).filter(e => e && e.id);

const match = events.find(e => (e.description || '').includes(phone));

if (!match) {
  return [{ json: { found: false, event_id: null, phone, tool_call_id: ctx.tool_call_id } }];
}
return [{ json: { found: true, event_id: match.id, summary: match.summary, start: match.start?.dateTime, phone, tool_call_id: ctx.tool_call_id } }];

const ctx = $('Merge Config + Tool').first().json;
const phone = ctx.tool_params.caller_phone || ctx.caller_number || '';
const newTime = ctx.tool_params.new_requested_time || ctx.tool_params.new_start_time || '';
const events = $input.all().map(i => i.json).filter(e => e && e.id);

const match = events.find(e => (e.description || '').includes(phone));

if (!match) {
  return [{ json: { found: false, event_id: '', new_start_time: newTime, tool_call_id: ctx.tool_call_id } }];
}
return [{ json: { found: true, event_id: match.id, new_start_time: newTime, tool_call_id: ctx.tool_call_id } }];
